// ✅ 필수값 검사
const body = $input.first().json.body || $input.first().json;

const required = ['prompt_p1', 'topic', 'keywords', 'category', 'use_media', 'upload_target'];
const missing = required.filter(k => !body[k]);

if (missing.length > 0) {
  throw new Error(`필수값 누락: ${missing.join(', ')}`);
}

// use_media 값 검증
if (!['auto', 'forced', 'off'].includes(body.use_media)) {
  throw new Error(`use_media 값 오류: ${body.use_media} (auto/forced/off 중 하나여야 함)`);
}

// upload_target 검증
if (body.upload_target !== 'youtube') {
  throw new Error(`upload_target 오류: ${body.upload_target} (현재 youtube만 지원)`);
}

// 이미지 슬롯 매핑 (IMG_1 ~ IMG_4)
const images = body.images || [];
const imageSlots = {};
for (let i = 0; i < 4; i++) {
  imageSlots[`IMG_${i + 1}`] = images[i] || null;
}

// 언어 감지 (한글 포함 여부)
const isKorean = /[\uAC00-\uD7A3]/.test(body.prompt_p1 + body.topic);
const translateMode = body.translate_mode || 'auto';
const needsTranslation = translateMode === 'on' || (translateMode === 'auto' && isKorean);

return [{
  json: {
    ...body,
    image_slots: imageSlots,
    prompt_lang_detected: isKorean ? 'ko' : 'en',
    needs_translation: needsTranslation,
    validated_at: new Date().toISOString()
  }
}];

const job = $input.first().json;

return [{
  json: {
    success: true,
    job_id: job.id,
    status: job.status,
    message: 'Job이 큐에 등록되었습니다.',
    created_at: job.created_at
  }
}];
